package com.evernorth.smartemp.service;
import com.evernorth.smartemp.dto.AuthDtos.*; import com.evernorth.smartemp.entity.User; import com.evernorth.smartemp.enums.Role; import com.evernorth.smartemp.exception.BadRequestException; import com.evernorth.smartemp.repository.UserRepository; import com.evernorth.smartemp.security.JwtUtil; import lombok.RequiredArgsConstructor; import org.springframework.security.authentication.*; import org.springframework.security.core.userdetails.*; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; import java.time.LocalDate; import java.util.*;
@Service @RequiredArgsConstructor public class AuthService { private final AuthenticationManager am; private final UserRepository repo; private final UserDetailsService uds; private final JwtUtil jwt; private final PasswordEncoder enc;
 public LoginResponse login(LoginRequest r){am.authenticate(new UsernamePasswordAuthenticationToken(r.getUsername(),r.getPassword())); User u=repo.findByUsername(r.getUsername()).orElseThrow(); UserDetails d=uds.loadUserByUsername(r.getUsername()); return LoginResponse.builder().token(jwt.generateToken(d)).id(u.getId()).username(u.getUsername()).firstName(u.getFirstName()).lastName(u.getLastName()).roles(d.getAuthorities().stream().map(a->a.getAuthority()).toList()).build();}
 public void register(RegisterRequest r){if(repo.existsByUsername(r.getUsername())||repo.existsByEmail(r.getEmail()))throw new BadRequestException("Username or email already exists"); User u=User.builder().username(r.getUsername()).email(r.getEmail()).password(enc.encode(r.getPassword())).firstName(r.getFirstName()).lastName(r.getLastName()).hireDate(LocalDate.now()).roles(Set.of(Role.EMPLOYEE)).build();repo.save(u);}
}
